  const [showNewOnly, setShowNewOnly] = useState(false);

  const filteredProducts = MOCK_PRODUCTS.filter(p => {
    const categoryMatch = selectedCategory === "Tout" || p.category === selectedCategory;
    const newMatch = !showNewOnly || p.isNew;
    return categoryMatch && newMatch;
  });

  return (
    <div className="space-y-8 animate-fade-in">

      {/* Header & Hero */}
      <div className="flex flex-col md:flex-row justify-between items-end gap-6 mb-8">
        <div>
          <h1 className="text-4xl md:text-5xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-white to-slate-400 mb-2">
            Lumina Market
          </h1>
          <p className="text-slate-400">Découvrez le futur de la technologie et du style.</p>
        </div>
      </div>

      {/* Filters Toolbar */}
      <div className="flex flex-wrap gap-4 items-center">
        <GlassCard className="!p-2 flex gap-2 !rounded-xl" hoverEffect={false}>
          {CATEGORIES.map(cat => (
            <button
              key={cat}
              onClick={() => setSelectedCategory(cat)}
              className={`
                px-4 py-2 rounded-lg text-sm font-medium transition-all
                ${selectedCategory === cat 
                  ? 'bg-cyan-500 text-white shadow-lg shadow-cyan-500/25' 
                  : 'hover:bg-white/5 text-slate-400'}
              `}
            >
              {cat}
            </button>
          ))}
        </GlassCard>

        <button
          onClick={() => setShowNewOnly(!showNewOnly)}
          className={`
            flex items-center gap-2 px-6 py-4 rounded-xl border transition-all glass-card
            ${showNewOnly ? 'border-amber-400/50 text-amber-300 bg-amber-400/10' : 'border-white/10 text-slate-400 hover:text-white'}
