import React, { useState } from 'react';
import { GlassCard } from '../components/GlassCard';
import { Search as SearchIcon, Sparkles, Loader } from 'lucide-react';
import { getShoppingAdvice } from '../services/geminiService';
import { MOCK_PRODUCTS } from '../constants';
import { Product } from '../types';

interface SearchProps {
  addToCart: (p: Product) => void;
}

export const Search: React.FC<SearchProps> = ({ addToCart }) => {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<Product[]>([]);
  const [aiAdvice, setAiAdvice] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!query.trim()) return;

    setLoading(true);
    setAiAdvice(null);
    setResults([]);

    // 1. Basic text search filter
    const basicResults = MOCK_PRODUCTS.filter(p => 
      p.name.toLowerCase().includes(query.toLowerCase()) || 
      p.category.toLowerCase().includes(query.toLowerCase())
    );
    setResults(basicResults);

    // 2. AI Advice
    try {
      const advice = await getShoppingAdvice(query, MOCK_PRODUCTS);
      setAiAdvice(advice);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto animate-fade-in">
      <h1 className="text-3xl font-bold mb-8">Recherche Intelligente</h1>

      <GlassCard className="mb-8" hoverEffect={false}>
        <form onSubmit={handleSearch} className="relative">
          <input
            type="text"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            placeholder="Ex: Je cherche quelque chose d'élégant pour le sport..."
            className="w-full bg-black/20 border border-white/10 rounded-xl py-4 pl-12 pr-4 text-white placeholder-slate-500 focus:outline-none focus:border-cyan-500/50 transition-all"
          />
          <SearchIcon className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={20} />
          <button 
            type="submit"
            className="absolute right-2 top-1/2 -translate-y-1/2 bg-cyan-600/80 hover:bg-cyan-500 text-white px-4 py-1.5 rounded-lg text-sm font-medium transition-colors"
          >
            Rechercher
          </button>
        </form>
      </GlassCard>

      {loading && (
        <div className="flex justify-center py-12">
          <Loader className="animate-spin text-cyan-400" size={32} />
        </div>
      )}

      {/* AI Advice Section */}
      {!loading && aiAdvice && (
        <GlassCard className="mb-8 border-cyan-500/30 bg-cyan-500/5" hoverEffect={false}>
          <div className="flex items-start gap-3">
            <Sparkles className="text-cyan-300 mt-1 flex-shrink-0" size={24} />
            <div>
              <h3 className="font-bold text-cyan-300 mb-2">Conseil de l'Assistant</h3>
              <p className="text-slate-200 leading-relaxed whitespace-pre-wrap">{aiAdvice}</p>
            </div>
          </div>
        </GlassCard>
      )}

      {/* Results Grid */}
      {!loading && results.length > 0 && (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {results.map(product => (
            <GlassCard key={product.id} className="flex gap-4 items-center group">
               <img src={product.image} alt={product.name} className="w-16 h-16 rounded-lg object-cover bg-black/30" />
               <div className="flex-1">
                 <h4 className="font-bold">{product.name}</h4>
                 <p className="text-sm text-slate-400">{product.price.toFixed(2)} €</p>
               </div>
               <button 
                 onClick={() => addToCart(product)}
                 className="px-4 py-2 bg-white/10 hover:bg-cyan-500 hover:text-white rounded-lg text-sm transition-colors"
               >
                 Voir
               </button>
            </GlassCard>
          ))}
        </div>
      )}

      {!loading && query && results.length === 0 && !aiAdvice && (
        <div className="text-center text-slate-500 py-12">
          Aucun résultat trouvé. Essayez des mots-clés différents.
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { HashRouter as Router, Routes, Route } from 'react-router-dom';
import { Layout } from './components/Layout';
import { Home } from './pages/Home';
import { Cart } from './pages/Cart';
import { Checkout } from './pages/Checkout';
import { Profile } from './pages/Profile';
import { Settings } from './pages/Settings';
import { Search } from './pages/Search';
import { Product, CartItem } from './types';

function App() {
  const [cartItems, setCartItems] = useState<CartItem[]>([]);

  const addToCart = (product: Product) => {
    setCartItems(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => 
          item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item
        );
      }
      return [...prev, { ...product, quantity: 1 }];
    });
  };

  const updateQuantity = (id: string, delta: number) => {
    setCartItems(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(0, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }).filter(item => item.quantity > 0));
  };

  const removeFromCart = (id: string) => {
    setCartItems(prev => prev.filter(item => item.id !== id));
  };

  const cartCount = cartItems.reduce((acc, item) => acc + item.quantity, 0);

  return (
    <Router>
      <Layout cartCount={cartCount}>
        <Routes>
          <Route path="/" element={<Home addToCart={addToCart} />} />
          <Route 
            path="/cart" 
            element={
              <Cart 
                items={cartItems} 
                updateQuantity={updateQuantity} 
                removeFromCart={removeFromCart} 
              />
            } 
          />
          <Route path="/checkout" element={<Checkout />} />
          <Route path="/search" element={<Search addToCart={addToCart} />} />
          <Route path="/profile" element={<Profile />} />
          <Route path="/settings" element={<Settings />} />
        </Routes>
      </Layout>
    </Router>
  );
}

export default App;

