import React, { useState } from 'react';
import { GlassCard } from '../components/GlassCard';
import { Search as SearchIcon, Sparkles, Loader } from 'lucide-react';
import { getShoppingAdvice } from '../services/geminiService';
import { MOCK_PRODUCTS } from '../constants';
import { Product } from '../types';

interface SearchProps {
  addToCart: (p: Product) => void;
}

export const Search: React.FC<SearchProps> = ({ addToCart }) => {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<Product[]>([]);
  const [aiAdvice, setAiAdvice] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!query.trim()) return;

    setLoading(true);
    setAiAdvice(null);
    setResults([]);

    // 1. Basic text search filter
    const basicResults = MOCK_PRODUCTS.filter(p => 
      p.name.toLowerCase().includes(query.toLowerCase()) || 
      p.category.toLowerCase().includes(query.toLowerCase())
    );
    setResults(basicResults);

    // 2. AI Advice
    try {
      const advice = await getShoppingAdvice(query, MOCK_PRODUCTS);
      setAiAdvice(advice);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto animate-fade-in">
      <h1 className="text-3xl font-bold mb-8 text-slate-900">Recherche Intelligente</h1>

      <GlassCard className="mb-8 p-2" hoverEffect={false}>
        <form onSubmit={handleSearch} className="relative">
          <input
            type="text"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            placeholder="Ex: Je cherche quelque chose d'élégant pour le sport..."
            className="w-full bg-slate-50 border border-slate-200 rounded-lg py-4 pl-12 pr-4 text-slate-900 placeholder-slate-400 focus:outline-none focus:border-cyan-500 focus:ring-1 focus:ring-cyan-500 transition-all"
          />
          <SearchIcon className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
          <button 
            type="submit"
            className="absolute right-2 top-1/2 -translate-y-1/2 bg-slate-900 hover:bg-slate-800 text-white px-6 py-2 rounded-md text-sm font-medium transition-colors"
          >
            Rechercher
          </button>
        </form>
      </GlassCard>

      {loading && (
        <div className="flex justify-center py-12">
          <Loader className="animate-spin text-cyan-600" size={32} />
        </div>
      )}

      {/* AI Advice Section */}
      {!loading && aiAdvice && (
        <GlassCard className="mb-8 border-cyan-200 bg-cyan-50/50" hoverEffect={false}>
          <div className="flex items-start gap-4">
            <div className="p-2 bg-white rounded-lg shadow-sm">
                <Sparkles className="text-cyan-600" size={24} />
            </div>
            <div>
              <h3 className="font-bold text-slate-900 mb-2">Conseil de l'Assistant</h3>
              <p className="text-slate-700 leading-relaxed whitespace-pre-wrap">{aiAdvice}</p>
            </div>
          </div>
        </GlassCard>
      )}

      {/* Results Grid */}
      {!loading && results.length > 0 && (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {results.map(product => (
            <GlassCard key={product.id} className="flex gap-4 items-center group">
               <img src={product.image} alt={product.name} className="w-16 h-16 rounded-lg object-cover bg-slate-100 border border-slate-200" />
               <div className="flex-1">
                 <h4 className="font-bold text-slate-900">{product.name}</h4>
                 <p className="text-sm text-cyan-600 font-medium">{product.price.toFixed(2)} €</p>
               </div>
               <button 
                 onClick={() => addToCart(product)}
                 className="px-4 py-2 bg-slate-100 hover:bg-cyan-600 hover:text-white rounded-lg text-sm text-slate-600 transition-colors font-medium"
               >
                 Voir
               </button>
            </GlassCard>
          ))}
        </div>
      )}

      {!loading && query && results.length === 0 && !aiAdvice && (
        <div className="text-center text-slate-400 py-12">
          Aucun résultat trouvé. Essayez des mots-clés différents.
        </div>
      )}
    </div>
  );
};

