import { GoogleGenAI } from "@google/genai";
import { Product } from "../types";

const apiKey = process.env.API_KEY;

export const getShoppingAdvice = async (query: string, availableProducts: Product[]): Promise<string> => {
  if (!apiKey) {
    return "Mode démonstration : Clé API non configurée. Veuillez ajouter votre clé API pour activer l'assistant intelligent.";
  }

  try {
    const ai = new GoogleGenAI({ apiKey });

    // Create a context-aware prompt with our product catalog
    const productList = availableProducts.map(p => `- ${p.name} (ID: ${p.id}, Catégorie: ${p.category}, Prix: ${p.price}€)`).join('\n');

    const prompt = `
      Tu es un assistant shopping personnel pour "SHELLOS", une boutique haut de gamme.

      Voici notre catalogue actuel :
      ${productList}

      La demande du client est : "${query}"

      Réponds au client de manière professionnelle, concise et élégante. 
      Recommande 1 ou 2 produits spécifiques de notre catalogue qui correspondent le mieux à sa demande.
      Explique pourquoi ces produits conviennent.
      Ne mentionne pas de produits qui ne sont pas dans la liste.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    return response.text || "Désolé, je n'ai pas pu analyser votre demande pour le moment.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Une erreur est survenue lors de la communication avec l'assistant intelligent.";
  }
};

