                 <p className="text-sm text-cyan-600 font-medium">{product.price.toFixed(2)} €</p>
               </div>
               <button 
                 onClick={(e) => {
                   e.stopPropagation();
                   addToCart(product);
                 }}
                 className="px-4 py-2 bg-slate-100 hover:bg-cyan-600 hover:text-white rounded-lg text-sm text-slate-600 transition-colors font-medium z-10 relative"
               >
                 + Panier
               </button>
            </GlassCard>
          ))}
        </div>
      )}

      {!loading && query && results.length === 0 && !aiAdvice && (
        <div className="text-center text-slate-400 py-12">
          Aucun résultat trouvé. Essayez des mots-clés différents.
        </div>
      )}
    </div>
  );
};

