import { GoogleGenAI, Type } from "@google/genai";
import { Product } from "../types";

const apiKey = process.env.API_KEY;

export interface AiSearchResponse {
  advice: string;
  recommendedProductIds: string[];
}

export const getShoppingAdvice = async (query: string, availableProducts: Product[]): Promise<AiSearchResponse> => {
  if (!apiKey) {
    return {
      advice: "Mode démonstration : Clé API non configurée. Veuillez ajouter votre clé API pour activer l'assistant intelligent.",
      recommendedProductIds: []
    };
  }

  try {
    const ai = new GoogleGenAI({ apiKey });

    // Create a context-aware prompt with our product catalog
    const productList = availableProducts.map(p => `- ${p.name} (ID: ${p.id}, Catégorie: ${p.category}, Prix: ${p.price}€, Description: ${p.description})`).join('\n');

    const prompt = `
      Tu es un assistant shopping expert pour "SHELLOS".

      CATALOGUE:
      ${productList}

      DEMANDE CLIENT: "${query}"

      TACHE:
      1. Analyse la demande.
      2. Sélectionne les meilleurs produits du catalogue (maximum 4).
      3. Rédige un conseil court et élégant.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            advice: {
              type: Type.STRING,
              description: "Un conseil court et professionnel pour le client."
            },
            recommendedProductIds: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
              description: "La liste des IDs exacts des produits recommandés."
            }
          }
        }
      }
    });

    if (response.text) {
      return JSON.parse(response.text) as AiSearchResponse;
    }

    return { advice: "Je n'ai pas pu trouver de produits correspondants.", recommendedProductIds: [] };

  } catch (error) {
    console.error("Gemini API Error:", error);
    return { 
      advice: "Une erreur est survenue lors de l'analyse intelligente. Voici les résultats de la recherche classique.", 
      recommendedProductIds: [] 
    };
  }
};

