import React, { createContext, useContext, useState } from 'react';
import { CATEGORY_BG_MAP } from '../constants';

interface BackgroundContextType {
  background: string;
  setBackground: (url: string) => void;
  setCategory: (category: string) => void;
}

const BackgroundContext = createContext<BackgroundContextType | undefined>(undefined);

export const BackgroundProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [background, setBackgroundState] = useState(CATEGORY_BG_MAP["Tout"]);

  const setBackground = (url: string) => {
    setBackgroundState(url);
  };

  const setCategory = (category: string) => {
    const bg = CATEGORY_BG_MAP[category] || CATEGORY_BG_MAP["Tout"];
    setBackgroundState(bg);
  };

  return (
    <BackgroundContext.Provider value={{ background, setBackground, setCategory }}>
      {children}
    </BackgroundContext.Provider>
  );
};

export const useBackground = () => {
  const context = useContext(BackgroundContext);
  if (!context) throw new Error('useBackground must be used within a BackgroundProvider');
  return context;
};

